var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여긴…….","JPN":"ここは……","ENG":"Where are we?","TWN":"這裡是……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"내성이로군요.","JPN":"内郭ですね。","ENG":"The inner castle, it seems.","TWN":"原來是城內。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"주변을 관찰해 보세요. 여기도 알렌 선생님의 집에 펼쳐져 있던 성벽 도시와 흡사하네요.","JPN":"周りを見てください。アレン先生の家から繋がっていた城郭都市に似ていますね。","ENG":"Look around you. It's similar to the walled city at Mr. Birmingham's place.","TWN":"你們看看周圍，是不是很類似那時候艾倫老師家的景象。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"규모가 더 큰 걸 봐서는 이쪽이 원본 같아요.","JPN":"規模がもっと大きいのを見るに、こちらが元のようです。","ENG":"Considering the bigger scale, this must be the original.","TWN":"只是規模更大，看來這裡應該才是真的。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이 도시의 지배자가 있다면 바로 저 안에 있을 거예요.","JPN":"この都市の支配者がいるならあの中にいるはずです。","ENG":"The city's ruler should be somewhere in there.","TWN":"這個城市的支配者應該就在那裡面。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"궁전 지하는 외부의 접근이 어려우니 사람을 감금해 두기도 적절하겠죠.","JPN":"宮殿の地下は外部からの侵入が難しいので、人を監禁しておくのに適切でしょう。","ENG":"The dungeons of the castle would be perfect to keep intruders out and prisoners in.","TWN":"宮殿的地下城難以與外界接觸，應該很適合用來監禁人。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"제대로 찾아온 것 같긴 한데…….","JPN":"ここで間違いないようだけど……","ENG":"This does look like the right place…","TWN":"好像是這裡沒錯……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어때, 유미나? 뭔가 느껴져?","JPN":"どう、ミナ？　何か感じる？","ENG":"Well, Mina? Can you feel anything?","TWN":"如何？劉米娜？有什麼反應嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 이 안으로 선배의 힘이 이어져 있어.","JPN":"うん。この中に先輩の力が繋がってる。","ENG":"Yeah. The signature of Shiyoon's power is coming from there.","TWN":"嗯，前輩就在那裡面！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"서두르자. 여기 올 때 느꼈던 것보다 힘이 더 약해졌어.","JPN":"急ごう。ここに来る時感じた力より弱まってる。","ENG":"Let's hurry though. The signature is weaker than when we first got here.","TWN":"動作快！前輩的力量似乎比我們來的時候更弱了。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마치…… 뭔가가 선배의 힘을 빨아들이고 있는 것처럼.","JPN":"まるで……何かが先輩の力を吸い込んでいるみたい。","ENG":"It's as if… something is sucking away his power.","TWN":"好像……有什麼東西正在吸取前輩的力量！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"좋아. 그럼 어서…….","JPN":"よし。それじゃあ早く……","ENG":"Okay, then. Let's hurry before-","TWN":"好！快……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"앗, 따거!","JPN":"痛っ！","ENG":"Ow, that stings!","TWN":"噢！好痛！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_07"},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜 그래? 갑자기?","JPN":"急にどうしたの？","ENG":"Huh? What's wrong?","TWN":"怎麼突然這樣？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"역장이 가로막고 있어. 역시 쉽게 들여보내 주진 않네.","JPN":"力場で遮られている。やっぱり簡単には入れてくれなさそう。","ENG":"There's a force field blocking the way. Of course they wouldn't make this easy.","TWN":"力場把路擋住了，果然沒這麼容易的事！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 힘으로 부수고 들어가면 어때?","JPN":"じゃあ、壊して入るのはどう？","ENG":"Why don't we just smash our way through?","TWN":"那還是靠蠻力硬闖如何？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"무식한 방법이지만 시도해봐서 나쁠 건 없겠지.","JPN":"単純な方法だけど、試してみて損はないだろうね。","ENG":"It's not very nuanced, but it's worth a try I guess.","TWN":"雖然有點魯莽，但試試看也不會少塊肉。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어때? 효과가 있어?","JPN":"どう？　効いた？","ENG":"Well? Did that work?","TWN":"怎麼樣？可以嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"틀렸어. 역시 꿈쩍도 안 해.","JPN":"ダメ。びくともしない。","ENG":"Not at all. It didn't even budge.","TWN":"不行，完全沒反應。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"출력을 더 올려서 공격해야 하나?","JPN":"出力をもっと上げて攻撃するべきかな。","ENG":"Should we ramp up the power and attack again?","TWN":"還是要加強破壞力道？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아니, 그렇게 소란을 일으켰다간 적들이 이곳으로 몰릴 수도 있어.","JPN":"いや、騒ぎを起こしたら敵にバレるかもしれない。","ENG":"No, if we cause a commotion, we might end up attracting enemies here.","TWN":"不行，萬一引起騷動，怕會打草驚蛇。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그리고 이건 물리적인 공격으로 파괴하기 불가능해 보여.","JPN":"あと、どうもこれは物理的な攻撃では破壊できないように見える。","ENG":"Besides, I don't think we can destroy this with physical attacks.","TWN":"而且這似乎無法靠蠻力破壞。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"파괴할 수 있었다면, 우리 둘이 공격했을 때 조금이라도 손상되었어야 해.","JPN":"破壊できるなら、私たち2人が攻撃した時に少しでも傷がついたはず。","ENG":"If it was destructible, our attacks should have damaged at least a little.","TWN":"要是靠蠻力有效的話，至少在我們攻擊時應該多少會有點受損。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이건 마치……. 공간 자체를 갈라 놓은 것 같아.","JPN":"これはまるで……空間自体を分離したみたい。","ENG":"It's as if… The space itself has been split into two.","TWN":"這感覺好像是……把空間分割開來。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇다고 갑자기 다른 방법을 찾을 수도 없잖아?","JPN":"でもすぐ他の方法を探すのも……","ENG":"But we're all out of options now…","TWN":"但現在也沒別的辦法啦？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그렇긴 한데…….","JPN":"まあ、そうだけど……","ENG":"True, but still…","TWN":"話是沒錯……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저기…… 미나야!","JPN":"あの……ミナちゃん！","ENG":"Hey… Mina?","TWN":"欸……米娜！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어쩌면 해제방법을 찾을 수 있을지도 몰라.","JPN":"もしかしたら解除方法が見つかるかもしれない。","ENG":"I think there might be a way.","TWN":"好像有辦法喔？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 정말이야?","JPN":"え？　本当に？","ENG":"What? For real?!","TWN":"真的嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응. 오면서 살펴봤는데 여기, 단순한 성은 아닌 것 같아.","JPN":"うん。来る途中に調べてたんだけど、ここは普通の城ではないと思う。","ENG":"Yeah. I took a closer look on the way, and this doesn't seem to be an ordinary castle.","TWN":"我們來路的上有觀察一下，這裡似乎不只是一座城？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"성이 아니라고? 내 눈에는 딱히 이상한 점이 안 보이던데?","JPN":"普通の城じゃない？　特に変わったところはなさそうだったよ？","ENG":"Really? I didn't notice anything strange though.","TWN":"不是城？但我沒看到什麼奇怪的地方啊？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"크흠. 그래도 마술사 지망생으로서 눈썰미는 남다르거든.","JPN":"えっへん。これでもマジシャンの卵として観察力は優れているの。","ENG":"Ahem. Well, let's just say I've got a keen eye as an aspiring magician.","TWN":"哼哼，未來的大魔術師看見的，和你看見的當然不一樣囉！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"멀리서 봤을 때랑 배치가 전혀 달라. 건물들도 뒤죽박죽이고.","JPN":"遠くから見た時と配置が全然違う。建物もごちゃごちゃしてるし。","ENG":"It's arranged completely different than when you see it from afar. The buildings are all mixed up too.","TWN":"遠遠看不覺得，近看發現景物全都不一樣，建築物也都雜亂無章。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러니까…… 전혀 다른 용도로 만들었는데 겉모습만 억지로 바꿔 놓은 느낌이야.","JPN":"だから……全然違う用途で作ったものを、見た目だけ無理やり変えた感じだよ。","ENG":"In other words… It's as if they changed its appearance by force, like it was built for a completely different purpose.","TWN":"我猜……應該是完全不同的用途，感覺只是換皮而已。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"확실히, 지금까지 거쳐 온 도로와 구획들도 지나치게 정돈된 인상이었죠.","JPN":"確かに、これまで通ってきた道や区画も、あまりにも整いすぎた印象がありました。","ENG":"That's true. The roads and sectors we passed seemed excessively organized.","TWN":"確實是，先前我們經過的道路或是區域都是很整齊的。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"현대의 계획도시 이상으로요.","JPN":"現代の計画都市以上にです。","ENG":"Even more so than deliberately designed modern cities.","TWN":"甚至還超越現代的城市呢。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나, 전투는 자신 없지만 이론 수업은 빠지지 않고 들었거든.","JPN":"私ね、戦闘には自信ないけど理論の授業は欠かさず聞いていたんだ。","ENG":"I'm terrible at combat, but I've been paying attention in theory class.","TWN":"戰鬥方面我不敢說，但理論課我可是從來都沒翹過課呢！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래서 쭉 생각해 봤는데…….","JPN":"それで、ずっと考えてみたんだけど……","ENG":"And it got me thinking…","TWN":"我從剛才就一直在想……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이건 관리국 차원함선의 구조도에 맞게 중세시대 건물을 배치한 것 같아.","JPN":"これは管理局の次元艦船の構造図に合わせて中世時代の建物を配置したみたい。","ENG":"I think they might have arranged medieval buildings to match the structure of an Administration dimensional ship.","TWN":"這應該是以管理局次元艦船的架構圖為基礎，再加上中世紀建築。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 차원함선?","JPN":"え？　次元艦船？","ENG":"What? A dimensional ship?","TWN":"什麼？次元艦船？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래! 관리국 표준 함선 구조를 엄청 크게 확대하면 딱 이대로야!","JPN":"そう！　管理局標準艦船の構造を大きく拡大したら、まさしくこのままだよ！","ENG":"That's right! If you zoom into a standard Administration ship, the layout looks exactly like this!","TWN":"沒錯！將管理局標準艦船放到最大後就長這樣！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"무, 물론 내가 들어도 말도 안 되는 소리 같긴 하지만……","JPN":"じ、自分で言っててもおかしい話だと思うけどね……","ENG":"O-of course, I realize that sounds ridiculous…","TWN":"我知道這聽起來很荒謬……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아. 방금 네가 말했잖아. 마술사 지망생이라 눈썰미는 남다르다고.","JPN":"大丈夫、さっき自分で言ったでしょ。マジシャンの卵として観察力に優れているって。","ENG":"It's fine. You said so yourself, right? You've got extra keen eyes as a prospective mage.","TWN":"不會啦，你剛不是有說嗎？你是未來的大魔術師，你看到的和我們看到的不一樣。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미카 넌 마술에 대해선 진지하니까. 아무렇게나 한 말은 아닐 거야.","JPN":"ミカは手品については真剣だから。適当なことは言わないと思う。","ENG":"I know how serious you are when it comes to magic. I'm sure you're not just making this up.","TWN":"米卡，你這麼認真看待魔術，我相信你不會亂說話的。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"……응! 맞아! 내 꿈을 걸고 맹세할 수 있어!","JPN":"……うん！　そうだよ！　私の夢をかけて誓える！","ENG":"…Yeah! That's right! I can swear upon my dream!","TWN":"……沒錯！我可以用我的夢想發誓！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 여긴 어떻게 통과해야 할까?","JPN":"じゃあ、ここはどうやって通過すればいいんだろう？","ENG":"So how are we going to get through here?","TWN":"那我們該如何通過這裡呢？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"위치상 지금 우리가 있는 곳은 전투정보실 입구일 거야.","JPN":"配置上だと、今私たちがいるところは戦闘情報室の入口だと思う。","ENG":"Based on our location, we're probably at the CIC's entrance.","TWN":"根據架構圖，現在我們所站的位置應該是戰鬥資料室的入口。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 전투정보실은 항상 보안 시스템이 가동되고 있어. 지금처럼.","JPN":"そして戦闘情報室は常にセキュリティシステムが稼動している。今みたいにね。","ENG":"CIC always has a security system running. Just like now.","TWN":"而戰鬥資料室通常都設有安全系統，就像現在這樣。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"보안 시스템의 에너지 공급장치만 파괴하면 역장이 사라질 거야!","JPN":"セキュリティシステムのエネルギー供給装置さえ破壊すれば、力場が消えるはずだよ！","ENG":"All we need to do is destroy the power source for the security system, and the barrier will be gone!","TWN":"所以只要破壞安全系統的動能補給裝置，力場應該就會消失！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 그럼 시간 끌지 말고 바로 시도해 보자.","JPN":"よし。じゃあ、さっそく試してみよう。","ENG":"Great. Then let's try it right away.","TWN":"好！那就不要浪費時間，馬上來試試看！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에너지 공급장치는 어디 있어?","JPN":"エネルギー供給装置はどこにあるの？","ENG":"Where's the power source?","TWN":"動能補給裝置在哪？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앗, 그게……. 나도 전문가는 아니라 그것까지는 잘 모르겠어.","JPN":"あっ、それは……私も専門家じゃないから、そこまではよくわからないの。","ENG":"Um... well... I'm not an expert on that, so I wouldn't know.","TWN":"這麼嘛……畢竟我也不是艦船架構專家，所以就只知道這麼多而已。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아……. 그렇지, 참. 다시 원점으로 돌아왔네.","JPN":"ああ……そうだよね。また振り出しに戻っちゃった。","ENG":"Oh... Right. So we're back to zero.","TWN":"喔……也是。那我們不就又回到原點嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"원점은 무슨 원점이야?","JPN":"振り出しって何の振り出し？","ENG":"No we're not.","TWN":"才不是原點！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그라운드 원에서 둘째 가라면 서러워 할 차원함선 애호가께서 우리 쪽에 계시는데.","JPN":"グラウンド・ワン一の次元艦船マニアが味方にいるじゃない。","ENG":"We know one of the biggest nerds in Ground One when it comes to dimensional ships.","TWN":"我們不是還有個說他是第二，沒人敢稱第一的次元艦船愛好者嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"누, 누구세요? 지금 좀 바쁜데……!","JPN":"だ、誰なのです？　今はちょっと忙しいんですけど……！","ENG":"W-who is it? I'm a little busy right now…","TWN":"請問哪裡找？我現在有點忙……！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……그래서 보안 시스템의 에너지 공급장치가 있을 만한 곳이 어딘지 알고 싶은데요, 과장님.","JPN":"……それで、セキュリティシステムの\\nエネルギー供給装置がありそうな場所を知りたいのですが、課長。","ENG":"…and so we'd like to know where we could find the power source to the security system.","TWN":"……科長，我想知道，安全系統的動能補給裝置可能會在哪裡？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"확실히…… 말을 듣고 보니 도시 모습이 차원 함선 구조랑 비슷하네요.","JPN":"確かに……話を聞く限り、都市の姿は次元艦船構造に似ていますね。","ENG":"Hmm… Come to think of it, the city does look very similar to a dimensional ship.","TWN":"嗯……這樣聽　起來，城市的架構確實和次元艦船很像呢。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"으음……. 그렇다면 여기와 여기요.","JPN":"うーん……それなら、こことここなのです。","ENG":"Hmm… Then I'd say it's here, and here.","TWN":"嗯，這樣的話……應該是這裡或這裡吧？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"보안 시스템의 에너지 공급장치는 안전성 때문에 병렬로 연결되거든요.","JPN":"セキュリティシステムのエネルギー供給装置は、安全性のために並列に繋がっているのです。","ENG":"In order to ensure stability, power supply devices for security systems are installed in a parallel layout.","TWN":"通常保險起見，安全系統的動能補給裝置都會連在一起的。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"교전 중에 하나가 멈춰도 다른 하나가 보안 시스템을 유지하게 되어 있어요.","JPN":"交戦中に1つが停止しても、もう1つがセキュリティシステムを維持するようになっているのです。","ENG":"The redundancy ensures that at least one of them can keep the security system powered, even if the other goes out.","TWN":"這樣在交戰過程中，萬一其中一個有什麼狀況，另一個也可以維持安全系統的運作。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"장갑이 두터워서 파괴하기도 쉽지 않을 거고요.","JPN":"装甲が頑丈なので破壊するのも容易ではないでしょう。","ENG":"And they're heavily armored, so it won't be easy to destroy them.","TWN":"但外殼很堅固，要破壞它可能沒那麼容易。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"역시. 바쁘신데 고마워요, 과장님.","JPN":"さすがです。忙しいのにありがとうございます、課長。","ENG":"Wow, that was thorough. Thank you for your time.","TWN":"我想也是！謝謝科長，那就不打擾你囉～"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"다들 잘 들었지?","JPN":"みんな聞いたよね？","ENG":"Did y'all hear that?","TWN":"大家都聽到了吧？！"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 지금부터 작전을 설명해 줄게.","JPN":"じゃあ、今から作戦を説明してあげる。","ENG":"Now, I'll walk you through the plan.","TWN":"那我們的作戰計畫如下，"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"나랑 학생회가 각각 에너지 공급장치를 하나씩 파괴할 거야.","JPN":"私と生徒会がそれぞれエネルギー供給装置を一つずつ破壊する。","ENG":"The kids from the Academy and I will destroy each of these power supplies.","TWN":"我和學生會各破壞一個動能補給裝置，"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그리고 미나 넌 여기서 대기하고 있다가 역장이 사라지는 순간 바로 진입해.","JPN":"ミナはここで待機して、力場が消えたらすぐに突入して。","ENG":"As for you, Mina, standby right here and slip through as soon as the barrier vanishes.","TWN":"米娜你就先在這裡，等到力場消失就立刻進去！"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"역장이 재생성되는 데 걸리는 시간은 얼마 안 돼. 주저하지 마.","JPN":"力場が再生するまでの猶予はほんの少しだから、ためらわないで。","ENG":"It won't take long for the barrier to regenerate. So don't hesitate.","TWN":"力場恢復的時間應該不會太久，所以你絕對不能有一點猶豫！"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"소란이 커지면 침식체들이 몰려올 거야. 괜찮겠어?","JPN":"破壊する音で侵食体が押し寄せてくると思うけど、大丈夫そう？","ENG":"Once there's a big bang, the C.O.s will start swarming here. You sure about this?","TWN":"我怕有騷動的話會引來侵蝕體，這樣沒問題嗎？"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네 걱정이나 해. 이 작전에서 제일 위험한 역할은 너니까.","JPN":"自分のことだけ心配して。この作戦で一番危険な役はあなたなんだから。","ENG":"Don't worry about us. If anything, you have the most dangerous job.","TWN":"你顧好你自己就好，在這個計劃中最危險的角色就是你。"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……확실히 그렇군요.","JPN":"……確かにそうですね。","ENG":"…It's definitely true.","TWN":"……確實是。"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 무슨 뜻이야?","JPN":"え？　どういう意味？","ENG":"Huh? What makes you say that?","TWN":"嗯？為什麼？"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"여기 오면서 느꼈는데, 밖에 있는 침식체들은 그렇게 위험한 편이 아니야.","JPN":"ここに来て感じたけど、外にいる侵食体はそこまでの脅威ではない。","ENG":"I noticed on the way here… Those C.O.s out there aren't all that dangerous.","TWN":"根據我的觀察，那些在外面的侵蝕體並不是很危險。"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"만약 상위 침식체가 나타나더라도 우린 에너지 공급장치만 파괴하고 퇴각하면 돼.","JPN":"もし上位侵食体が現れても、私たちはエネルギー供給装置だけ破壊して退却すればいい。","ENG":"Even if a stronger one appears, all we need to do is destroy the power supplies and bail.","TWN":"萬一真的出現高階侵蝕體，我們也只要趕緊將動能補給裝置破壞後撤退就好。"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만 여긴 분명 CSE 4레벨 지역이야.","JPN":"でもここは、間違いなくCSE4レベルのエリア。","ENG":"But remember, this is a CSE level 4 area.","TWN":"但這裡CSE 4級地區，"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그 말은 네가 들어갈 저 안에 4종 침식체가 있을 가능성이 크다는 뜻이지.","JPN":"つまり、あなたが向かう先に第4種侵食体がいる可能性が高いってこと。","ENG":"Which means it's most likely there's a Category 4 in there… where you're about to go.","TWN":"意思就是，你要進去的地方有4類侵蝕體的可能性非常高。"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그러니까 네가 결정해. 작전을 진행할지 말지.","JPN":"だからあなたが決めて。作戦を実行するかどうか。","ENG":"So it's really up to you. Should we proceed with this plan or not?","TWN":"所以要不要執行這個計畫的決定權在你手上。"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……선배한테는 빚진 게 많아.","JPN":"……先輩には借りが多い。","ENG":"I owe Shiyoon big time.","TWN":"……我欠前輩太多了，"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이번 기회에 조금은 이자를 갚아 둬야지.","JPN":"この機会に、少しは返しておかないと。","ENG":"This is my chance to pay him back and then some.","TWN":"趁這個機會還他一點利息也好。"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"좋아. 결정됐네.","JPN":"よし。じゃあ決まりだね。","ENG":"Fine. That settles it then.","TWN":"很好，那就這麼決定囉！"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"다들 방심하지 마! 작전 개시!","JPN":"みんな、油断しないで！　作戦開始！","ENG":"Stay on your guard, everyone! This mission is a go!","TWN":"大家注意！作戰開始！"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"}]`);export{e as default};